from priorityQueue import PriorityQueue


def uniform_cost_search(graph, start, goal, weight_mapping):
    """
    Uniform-cost search: finds the shortest path in a weighted graph by always
    expanding the frontier node with lowest cumulative cost. Explores nodes in
    order of distance from start, making it optimal for non-negative edge weights.

    Inputs:
    [graph]: graph.Graph object
    [start]: start vertex (graph.Vertex instance)
    [goal]: goal vertex (graph.Vertex instance)
    [weight_mapping]: dict mapping edges to their weights

    Outputs:
    [path]: list of vertex elements from start to goal, or empty list if unreachable
    [cost]: total path cost, or float('inf') if no path exists
    """

    if start == goal:
        return [start.element()], 0

    frontier = PriorityQueue()
    frontier.add(start, 0)
    visited = set()
    cost_so_far = {start: 0}
    came_from = {start: None}

    while True:
        try:
            current = frontier.pop()
        except KeyError:
            return [], float('inf')

        if current == goal:
            path = []
            node = goal
            while node is not None:
                path.append(node.element())
                node = came_from[node]
            path.reverse()
            return path, cost_so_far[goal]

        visited.add(current)

        for edge in graph.incident_edges(current, outgoing=True):
            neighbor = edge.opposite(current)

            if neighbor not in visited:
                new_cost = cost_so_far[current] + weight_mapping[edge]

                if neighbor not in cost_so_far or new_cost < cost_so_far[neighbor]:
                    cost_so_far[neighbor] = new_cost
                    came_from[neighbor] = current
                    frontier.add(neighbor, new_cost)

    return [], float('inf')

